import asyncio
import json
from collections import defaultdict
import websockets

# A dict to keep track of all connected clients
clients = set()
# A dict for inventory system, using player IDs as keys
inventories = {}

async def handler(websocket, path):
    # Register new client on connection
    clients.add(websocket)
    
    # Get the connected user's id from websocket
    user_id = await getUserIdFromWebsocket(websocket) 

    if not inventories.get(user_id):
        inventories[user_id] = defaultdict(int) 
    
    try:
        async for message in websocket:
            data = json.loads(message)
            
            action = data['action']
            
            if action == 'addItem':
                itemId = data['item_id']
                inventories[user_id][itemId] += 1
                
                await notifyInventoryUpdateToOtherClients(websocket, user_id) 
        
    finally:
        clients.remove(websocket)

async def getUserIdFromWebsocket(websocket):
    # Dummy implementation of getting the id from a websocket
    return 'user1'  

async def notifyInventoryUpdateToOtherClients(source_websocket, user_id):
    for client in clients:
        if client != source_websocket and await getUserIdFromWebsocket(client) == user_id: 
            inventory_update = json.dumps({'event': 'inventoryUpdate', 'data': dict(inventories[user_id])})
            
            await client.send(inventory_update)  

start_server = websockets.serve(handler, 'localhost', 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()